update sys_dict_data
dict_sort = #{dictSort}, dict_label = #{dictLabel}, dict_value = #{dictValue}, dict_type = #{dictType}, css_class = #{cssClass}, rule = #{rule}, range_rule = #{rangeRule}, key_map = #{keyMap}, value_map = #{valueMap}, is_default = #{isDefault}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, dict_type_affiliation = #{dictTypeAffiliation}, rule_type = #{ruleType}, original_system = #{originalSystem}, uuid = #{uuid}, update_time = sysdate()
