mapper.select:
SELECT MIN(sdd.dict_code) AS dict_code, sdd.uuid, MIN(sdd.dict_sort) AS dict_sort, MIN(sdd.dict_label) AS dict_label, MIN(sdd.dict_value) AS dict_value, sdd.dict_type, MIN(sdd.css_class) AS css_class, MIN(sdd.rule) AS rule, MIN(sdd.range_rule) AS range_rule, MIN(sdd.is_default) AS is_default, MIN(sdd.status) AS status, MIN(sdd.create_by) AS create_by, MIN(sdd.create_time) AS create_time, MIN(sdd.update_by) AS update_by, MIN(sdd.update_time) AS update_time, MIN(sdd.remark) AS remark, MIN(sdd.dict_type_affiliation) AS dict_type_affiliation, MIN(sdd.rule_type) AS rule_type, MIN(sdt.dict_name) AS dict_type_str, MIN(sdd2.dict_label) AS dict_type_affiliation_str, JSON_ARRAYAGG( CASE WHEN sdd.original_system IS NOT NULL AND sdd.key_map IS NOT NULL THEN JSON_OBJECT('system', sdd.original_system, 'key', sdd.key_map) ELSE NULL END ) AS key_map_agg, JSON_ARRAYAGG( sdd.value_map ) AS value_map_agg FROM sys_dict_data sdd LEFT JOIN sys_dict_type sdt ON sdd.dict_type = sdt.dict_type LEFT JOIN sys_dict_data sdd2 ON sdd.dict_type_affiliation = sdd2.dict_code
sdd.dict_type = 'vehicle_attribute'
AND sdd.dict_type_affiliation = #{dictData.dictTypeAffiliation}
AND sdd.dict_label LIKE CONCAT('%', #{dictData.dictLabel}, '%')
AND sdd.dict_value LIKE CONCAT('%', #{dictData.dictValue}, '%')
AND sdd.status = #{dictData.status}
AND sdd.rule_type = #{dictData.ruleType}
GROUP BY sdd.uuid, sdd.dict_type ORDER BY MIN(sdd.dict_sort) ASC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1) FROM (
SELECT sdd.uuid
FROM sys_dict_data sdd

	sdd.dict_type = 'vehicle_attribute'

		AND sdd.dict_type_affiliation = #{dictTypeAffiliation}


		AND sdd.dict_label LIKE CONCAT('%', #{dictLabel}, '%')


		AND sdd.dict_value LIKE CONCAT('%', #{dictValue}, '%')


		AND sdd.status = #{status}


